87	// Strategy: Build L-shaped walls in two opposite corners, sealing off pet-free zones.
88	// Each corner has 2 free boundary walls, so only need 2 wall segments.
89	// This is much cheaper than full horizontal walls and adapts to pet positions.
90	
91	struct CornerPlan {
92	    int corner; // 0=TL, 1=TR, 2=BL, 3=BR
93	    int wall_row; // the horizontal wall row
94	    int wall_col; // the vertical wall column
95	    int area;
96	    int cost; // number of wall cells needed
97	    int pets_inside;
98	    double score;
99	    // The sealed region boundaries
100	    int r_min, r_max, c_min, c_max;
101	};
102	
103	// Wall cells for a corner plan
104	std::vector<Point> get_wall_cells(const CornerPlan& plan) {
105	    std::vector<Point> cells;
106	    if (plan.corner == 0) { // Top-Left: wall at row wall_row (cols 1..wall_col), col wall_col (rows 1..wall_row-1)
107	        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
108	        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
109	    } else if (plan.corner == 1) { // Top-Right: wall at row wall_row (cols wall_col..30), col wall_col (rows 1..wall_row-1)
110	        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
111	        for (int r = 1; r < plan.wall_row; r++) cells.push_back({r, plan.wall_col});
112	    } else if (plan.corner == 2) { // Bottom-Left: wall at row wall_row (cols 1..wall_col), col wall_col (rows wall_row+1..30)
113	        for (int c = 1; c <= plan.wall_col; c++) cells.push_back({plan.wall_row, c});
114	        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
115	    } else { // Bottom-Right: wall at row wall_row (cols wall_col..30), col wall_col (rows wall_row+1..30)
116	        for (int c = plan.wall_col; c <= GRID_SIZE; c++) cells.push_back({plan.wall_row, c});
117	        for (int r = plan.wall_row + 1; r <= GRID_SIZE; r++) cells.push_back({r, plan.wall_col});
118	    }
119	    return cells;
120	}
121	
122	bool is_safe_side(const CornerPlan& plan, int r, int c) {
123	    return r >= plan.r_min && r <= plan.r_max && c >= plan.c_min && c <= plan.c_max;
124	}
125	
126	// Find the best pair of corners (opposite corners)
127	CornerPlan plans[2];
128	int num_plans;
129	
130	void find_best_corner(int corner_id, CornerPlan& best) {
131	    best.score = -1;
132	
133	    for (int wr = 2; wr <= 29; wr++) {
134	        for (int wc = 2; wc <= 29; wc++) {
135	            int pets_inside = 0;
136	            int area = 0;
137	            int cost = 0;
138	            int r_min, r_max, c_min, c_max;
139	
140	            if (corner_id == 0) { // Top-Left: sealed region [1..wr-1] x [1..wc-1]
141	                r_min = 1; r_max = wr - 1; c_min = 1; c_max = wc - 1;
142	                cost = wc + (wr - 1); // horizontal wall has wc cells, vertical has wr-1 cells
143	            } else if (corner_id == 1) { // Top-Right: sealed region [1..wr-1] x [wc+1..30]
144	                r_min = 1; r_max = wr - 1; c_min = wc + 1; c_max = GRID_SIZE;
145	                cost = (GRID_SIZE - wc + 1) + (wr - 1);
146	            } else if (corner_id == 2) { // Bottom-Left: sealed region [wr+1..30] x [1..wc-1]
147	                r_min = wr + 1; r_max = GRID_SIZE; c_min = 1; c_max = wc - 1;
148	                cost = wc + (GRID_SIZE - wr);
149	            } else { // Bottom-Right: sealed region [wr+1..30] x [wc+1..30]
150	                r_min = wr + 1; r_max = GRID_SIZE; c_min = wc + 1; c_max = GRID_SIZE;
151	                cost = (GRID_SIZE - wc + 1) + (GRID_SIZE - wr);
152	            }
153	
154	            area = (r_max - r_min + 1) * (c_max - c_min + 1);
155	            if (area < 50) continue; // too small
156	            if (cost > 40) continue; // too expensive
157	
158	            int pets_near = 0; // pets on the wall boundary that could leak
159	            for (auto& p : pets) {
160	                if (p.r >= r_min && p.r <= r_max && p.c >= c_min && p.c <= c_max) {
161	                    pets_inside++;
162	                }
163	                // Count pets that are on the wall line itself (adjacent to safe zone)
164	                bool on_h_wall = false, on_v_wall = false;
165	                if (corner_id == 0 || corner_id == 1) {
166	                    on_h_wall = (p.r == wr && p.c >= c_min && p.c <= c_max);
167	                    on_v_wall = (p.c == wc && p.r >= r_min && p.r <= r_max);
168	                } else {
169	                    on_h_wall = (p.r == wr && p.c >= c_min && p.c <= c_max);
170	                    on_v_wall = (p.c == wc && p.r >= r_min && p.r <= r_max);
171	                }
172	                if (on_h_wall || on_v_wall) pets_near++;
173	            }
174	
175	            double base_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);
176	
177	            // Penalize by construction cost
178	            double time_factor = 1.0 / (1.0 + cost * 0.01);
179	
180	            // Reward 0 pets inside; penalize pets more for leakage risk
181	            double pet_bonus = (pets_inside == 0) ? 2.0 : std::pow(0.7, pets_inside);
182	            // Penalize pets near the wall boundary (leakage risk during construction)
183	            double near_penalty = 1.0 / (1.0 + pets_near * 0.1);
184	
185	            // Penalize by average human distance to the wall region
186	            double avg_human_dist = 0;
187	            for (int hi = 0; hi < M; hi++) {
188	                int dr = 0, dc = 0;
189	                if (humans[hi].r < r_min) dr = r_min - humans[hi].r;
190	                else if (humans[hi].r > r_max) dr = humans[hi].r - r_max;
191	                if (humans[hi].c < c_min) dc = c_min - humans[hi].c;
192	                else if (humans[hi].c > c_max) dc = humans[hi].c - c_max;
193	                avg_human_dist += dr + dc;
194	            }
195	            avg_human_dist /= M;
196	            double dist_factor = 1.0 / (1.0 + avg_human_dist * 0.02);
197	
198	            double score = base_score * time_factor * pet_bonus * dist_factor * near_penalty;
199	
200	            if (score > best.score) {
201	                best.corner = corner_id;
202	                best.wall_row = wr;
203	                best.wall_col = wc;
204	                best.area = area;
205	                best.cost = cost;
206	                best.pets_inside = pets_inside;
207	                best.score = score;
208	                best.r_min = r_min;
209	                best.r_max = r_max;
210	                best.c_min = c_min;
211	                best.c_max = c_max;
212	            }
213	        }
214	    }
215	}
216	
217	// Also compute dual horizontal wall score for comparison
218	double compute_dual_wall_score(int tr, int br) {
219	    int pets_above = 0, pets_below = 0;
220	    for (auto& p : pets) {
221	        if (p.r < tr) pets_above++;
222	        else if (p.r > br) pets_below++;
223	    }
224	    int area_above = (tr - 1) * GRID_SIZE;
225	    int area_below = (GRID_SIZE - br) * GRID_SIZE;
226	    double sa = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
227	    double sb = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);
228	    return (sa + sb) / 2.0;
229	}
230	
231	// Mode: 0 = dual L-shape, 1 = dual horizontal walls (fallback)
232	int strategy_mode;
233	int dual_wall_top, dual_wall_bot;
234	
235	void choose_strategy() {
236	    // Find best corner plans for each corner
237	    CornerPlan corners[4];
238	    for (int i = 0; i < 4; i++) {
239	        find_best_corner(i, corners[i]);
240	    }
241	
242	    // Best pair of any two corners (check all 6 pairs, not just opposite)
243	    double best_pair_score = -1;
244	    int best_pair[2] = {0, 3};
245	
246	    for (int a = 0; a < 4; a++) {
247	        for (int b = a + 1; b < 4; b++) {
248	            // Check that the two plans don't overlap in their sealed regions
249	            bool overlap = !(plans[0].r_max < plans[1].r_min || plans[1].r_max < plans[0].r_min ||
250	                           plans[0].c_max < plans[1].c_min || plans[1].c_max < plans[0].c_min);
251	            // Use corners a and b
252	            int r_min_a = corners[a].r_min, r_max_a = corners[a].r_max;
253	            int c_min_a = corners[a].c_min, c_max_a = corners[a].c_max;
254	            int r_min_b = corners[b].r_min, r_max_b = corners[b].r_max;
255	            int c_min_b = corners[b].c_min, c_max_b = corners[b].c_max;
256	
257	            bool regions_overlap = !(r_max_a < r_min_b || r_max_b < r_min_a ||
258	                                    c_max_a < c_min_b || c_max_b < c_min_a);
259	            if (regions_overlap) continue;
260	
261	            double combined = corners[a].score + corners[b].score;
262	            if (combined > best_pair_score) {
263	                best_pair_score = combined;
264	                best_pair[0] = a;
265	                best_pair[1] = b;
266	            }
267	        }
268	    }
269	
270	    // Also try single best corner (all humans in one corner)
271	    double best_single_score = -1;
272	    int best_single = 0;
273	    for (int i = 0; i < 4; i++) {
274	        if (corners[i].score > best_single_score) {
275	            best_single_score = corners[i].score;
276	            best_single = i;
277	        }
278	    }
279	
280	    // Compare with dual horizontal walls
281	    double best_dual_h = -1;
282	    int best_tr = 8, best_br = 23;
283	    for (int tr = 3; tr <= 15; tr++) {
284	        for (int br = tr + 4; br <= 28; br++) {
285	            double s = compute_dual_wall_score(tr, br);
286	            if (s > best_dual_h) {
287	                best_dual_h = s;
288	                best_tr = tr;
289	                best_br = br;
290	            }
291	        }
292	    }
293	
294	    // Choose strategy
295	    // L-shape advantages: faster build, better pet isolation when corners are clean
296	    // Give L-shape a 20% bonus for faster construction
297	    double l_pair_effective = best_pair_score * 1.2;
298	    double l_single_effective = best_single_score * 1.3; // single is even faster
299	
300	    if (l_pair_effective > best_dual_h && l_pair_effective > l_single_effective) {
301	        strategy_mode = 0;
302	        num_plans = 2;
303	        plans[0] = corners[best_pair[0]];
304	        plans[1] = corners[best_pair[1]];
305	    } else if (l_single_effective > best_dual_h) {
306	        strategy_mode = 0;
307	        num_plans = 1;
308	        plans[0] = corners[best_single];
309	    } else {
310	        strategy_mode = 1;
311	        dual_wall_top = best_tr;
312	        dual_wall_bot = best_br;
313	    }
314	}
315	
316	// Human assignment for L-shape strategy
317	int human_plan_assignment[10]; // which plan (0 or 1)
318	
319	// Wall cells to build for each plan
320	std::vector<Point> plan_walls[2];
321	
322	void assign_humans_lshape() {
323	    if (num_plans == 1) {
324	        for (int i = 0; i < M; i++) human_plan_assignment[i] = 0;
325	        return;
326	    }
327	
328	    // Allocate proportionally to wall cost, but ensure min 2 per plan
329	    int cost0 = plans[0].cost;
330	    int cost1 = plans[1].cost;
331	    int count0 = std::max(2, std::min(M - 2, (int)std::round((double)M * cost0 / (cost0 + cost1))));
332	
333	    std::vector<std::pair<double, int>> preference(M);
334	    for (int i = 0; i < M; i++) {
335	        double cr0 = (plans[0].r_min + plans[0].r_max) / 2.0;
336	        double cc0 = (plans[0].c_min + plans[0].c_max) / 2.0;
337	        double d0 = std::abs(humans[i].r - cr0) + std::abs(humans[i].c - cc0);
338	
339	        double cr1 = (plans[1].r_min + plans[1].r_max) / 2.0;
340	        double cc1 = (plans[1].c_min + plans[1].c_max) / 2.0;
341	        double d1 = std::abs(humans[i].r - cr1) + std::abs(humans[i].c - cc1);
342	
343	        preference[i] = {d0 - d1, i};
344	    }
345	    std::sort(preference.begin(), preference.end());
346	
347	    int assigned0 = 0;
348	    for (auto& [pref, idx] : preference) {
349	        if (assigned0 < count0) {
350	            human_plan_assignment[idx] = 0;
351	            assigned0++;
352	        } else {
353	            human_plan_assignment[idx] = 1;
354	        }
355	    }
356	}
357	
358	// For dual horizontal wall fallback
359	int human_wall_assignment_h[10]; // 0=top, 1=bot
360	
361	void assign_humans_dual_h() {
362	    int top_count = M / 2;
363	    std::vector<std::pair<int, int>> preference(M);
364	    for (int i = 0; i < M; i++) {
365	        preference[i] = {std::abs(humans[i].r - dual_wall_top) - std::abs(humans[i].r - dual_wall_bot), i};
366	    }
367	    std::sort(preference.begin(), preference.end());
368	    int assigned_top = 0;
369	    for (auto& [pref, idx] : preference) {
370	        if (assigned_top < top_count) {
371	            human_wall_assignment_h[idx] = 0;
372	            assigned_top++;
373	        } else {
374	            human_wall_assignment_h[idx] = 1;
375	        }
376	    }
377	}
378	
379	int main() {
380	    std::ios_base::sync_with_stdio(false);
381	    std::cin.tie(NULL);
382	
383	    std::cin >> N;
384	    pets.resize(N);
385	    pet_types.resize(N);
386	    for (int i = 0; i < N; i++) {
387	        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
388	    }
389	
390	    std::cin >> M;
391	    humans.resize(M);
392	    for (int i = 0; i < M; i++) {
393	        std::cin >> humans[i].r >> humans[i].c;
394	    }
395	
396	    memset(grid, false, sizeof(grid));
397	    choose_strategy();
398	
399	    if (strategy_mode == 0) {
400	        // L-shape mode
401	        for (int p = 0; p < num_plans; p++) {
402	            plan_walls[p] = get_wall_cells(plans[p]);
403	        }
404	        assign_humans_lshape();
405	    } else {
406	        // Dual horizontal wall mode
407	        assign_humans_dual_h();
408	    }
409	
410	    for (int turn = 0; turn < NUM_TURNS; turn++) {
411	        std::string actions(M, '.');
412	        std::vector<Point> walls_being_built;
413	
414	        if (strategy_mode == 0) {
415	            // L-shape strategy
416	            for (int i = 0; i < M; i++) {
417	                int my_plan = human_plan_assignment[i];
418	                auto& my_walls = plan_walls[my_plan];
419	                auto& plan = plans[my_plan];
420	
421	                // Find best unbuilt wall cell: balance proximity to human and priority from corner outward
422	                int best_idx = -1;
423	                int best_priority = INF;
424	
425	                // The intersection point of the L-shape
426	                int corner_r = plan.wall_row;
427	                int corner_c = plan.wall_col;
428	
429	                for (int w = 0; w < (int)my_walls.size(); w++) {
430	                    Point wc = my_walls[w];
431	                    if (grid[wc.r][wc.c]) continue;
432	
433	                    // Check not already claimed this turn
434	                    bool claimed = false;
435	                    for (auto& wb : walls_being_built) {
436	                        if (wb == wc) { claimed = true; break; }
437	                    }
438	                    if (claimed) continue;
439	
440	                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
441	                    // Distance from corner intersection (build from corner outward)
442	                    int corner_dist = std::abs(wc.r - corner_r) + std::abs(wc.c - corner_c);
443	                    // Combined priority: mostly distance but with a small bias toward corner
444	                    int priority = dist * 2 + corner_dist;
445	                    if (priority < best_priority) {
446	                        best_priority = priority;
447	                        best_idx = w;
448	                    }
449	                }
450	
451	                if (best_idx == -1) {
452	                    // All walls built - move to center of safe zone
453	                    int tr = (plan.r_min + plan.r_max) / 2;
454	                    int tc = (plan.c_min + plan.c_max) / 2;
455	                    Point target = {tr, tc};
456	                    if (!passable(target.r, target.c)) {
457	                        // Find any passable cell in safe zone
458	                        bool found = false;
459	                        for (int r = plan.r_min; r <= plan.r_max && !found; r++) {
460	                            for (int c = plan.c_min; c <= plan.c_max && !found; c++) {
461	                                if (passable(r, c)) {
462	                                    target = {r, c};
463	                                    found = true;
464	                                }
465	                            }
466	                        }
467	                    }
468	                    if (humans[i] != target) {
469	                        actions[i] = move_toward(humans[i], target);
470	                    }
471	                } else {
472	                    Point wall_target = my_walls[best_idx];
473	
474	                    // Find a position adjacent to wall_target from the SAFE side
475	                    Point stand_pos = {-1, -1};
476	                    int best_stand_dist = INF;
477	
478	                    for (int d = 0; d < 4; d++) {
479	                        int sr = wall_target.r + DR[d];
480	                        int sc = wall_target.c + DC[d];
481	                        if (!passable(sr, sc)) continue;
482	
483	                        // Prefer standing inside the safe zone
484	                        bool in_safe = is_safe_side(plan, sr, sc);
485	
486	                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
487	                        // Give big bonus to safe-side positions
488	                        int effective_dist = in_safe ? dist : dist + 100;
489	
490	                        if (effective_dist < best_stand_dist) {
491	                            best_stand_dist = effective_dist;
492	                            stand_pos = {sr, sc};
493	                        }
494	                    }
495	
496	                    if (stand_pos.r == -1) {
497	                        // Can't find standing position, try any adjacent
498	                        for (int d = 0; d < 4; d++) {
499	                            int sr = wall_target.r + DR[d];
500	                            int sc = wall_target.c + DC[d];
501	                            if (passable(sr, sc)) {
502	                                stand_pos = {sr, sc};
503	                                break;
504	                            }
505	                        }
506	                    }
507	
508	                    if (stand_pos.r == -1) {
509	                        actions[i] = '.';
510	                    } else if (humans[i] == stand_pos) {
511	                        // Build the wall
512	                        if (can_build_wall(wall_target.r, wall_target.c)) {
513	                            for (int d = 0; d < 4; d++) {
514	                                if (humans[i].r + DR[d] == wall_target.r &&
515	                                    humans[i].c + DC[d] == wall_target.c) {
516	                                    actions[i] = BUILD_CH[d];
517	                                    walls_being_built.push_back(wall_target);
518	                                    break;
